import javax.crypto.Cipher;
import javax.crypto.spec.GCMParameterSpec;
import javax.crypto.spec.SecretKeySpec;
import java.security.MessageDigest;
import java.security.SecureRandom;
import java.util.Arrays;
import java.util.Base64;

class OracleAdapter {
    static byte[] aesKey(String key) throws Exception {
        byte[] sha = MessageDigest.getInstance("SHA-256").digest(key.getBytes("UTF-8"));
        return Arrays.copyOf(sha, 16);                       // first 16 bytes of SHA-256(key)
    }
    static String encrypt(String pt, byte[] k) throws Exception {
        byte[] nonce = new byte[12];
        new SecureRandom().nextBytes(nonce);                 // fresh 12-byte GCM nonce
        Cipher c = Cipher.getInstance("AES/GCM/NoPadding");
        c.init(Cipher.ENCRYPT_MODE, new SecretKeySpec(k, "AES"), new GCMParameterSpec(128, nonce));
        byte[] ctTag = c.doFinal(pt.getBytes("UTF-8"));      // ciphertext || 128-bit tag
        byte[] all = new byte[12 + ctTag.length];
        System.arraycopy(nonce, 0, all, 0, 12);
        System.arraycopy(ctTag, 0, all, 12, ctTag.length);
        return Base64.getEncoder().encodeToString(all);
    }
    // THE ORACLE: the GCM tag is verified inside doFinal; any tamper -> AEADBadTagException -> "".
