        try {
            byte[] all = Base64.getDecoder().decode(cookie);
            byte[] nonce = Arrays.copyOfRange(all, 0, 12);
            byte[] ctTag = Arrays.copyOfRange(all, 12, all.length);
            Cipher c = Cipher.getInstance("AES/GCM/NoPadding");
            c.init(Cipher.DECRYPT_MODE, new SecretKeySpec(k, "AES"), new GCMParameterSpec(128, nonce));
            return Base64.getEncoder().encodeToString(c.doFinal(ctTag));
        } catch (Exception e) {
            return "";                                       // uniform empty on ANY failure
