package com.acme.hr.auth;

import org.apache.shiro.crypto.AesCipherService;
import org.apache.shiro.crypto.OperationMode;
import org.apache.shiro.util.ByteSource;
import java.util.Base64;

/** Mints and verifies HR login tokens with Shiro's authenticated (GCM) AesCipherService. */
public class SecureTokenService {

    private final AesCipherService cipher = new AesCipherService();
    private final byte[] key;

    public SecureTokenService(byte[] key) {
        this.key = key;
        cipher.setMode(OperationMode.GCM);
        cipher.setStreamingMode(OperationMode.GCM);
    }

    public String mint(byte[] claim) {
        ByteSource out = cipher.encrypt(claim, key);          // nonce || ciphertext || tag
        return Base64.getEncoder().encodeToString(out.getBytes());
    }

    public byte[] verify(String token) {
        byte[] raw = Base64.getDecoder().decode(token);
        ByteSource claim = cipher.decrypt(raw, key);          // AEAD tag checked during decrypt
        return claim.getBytes();
    }
}
```

