package edu.lms.security;

import org.apache.shiro.crypto.AesCipherService;
import org.apache.shiro.crypto.OperationMode;
import org.apache.shiro.util.ByteSource;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.stereotype.Component;
import java.util.Base64;

/** Spring component encrypting/decrypting the LMS session cookie with GCM. */
@Component
public class SessionCookieCodec {

    private final AesCipherService cipher;
    private final byte[] key;

    public SessionCookieCodec(@Value("${lms.remember.key}") byte[] key) {
        this.key = key;
        AesCipherService c = new AesCipherService();
        c.setMode(OperationMode.GCM);                 // built once at construction
        c.setStreamingMode(OperationMode.GCM);
        this.cipher = c;
    }

    public String write(byte[] enrollment) {
        return Base64.getEncoder().encodeToString(cipher.encrypt(enrollment, key).getBytes());
    }

    public byte[] read(String cookie) {
        ByteSource claim = cipher.decrypt(Base64.getDecoder().decode(cookie), key);
        return claim.getBytes();
    }
}
