import javax.crypto.Cipher;
import javax.crypto.spec.GCMParameterSpec;
import javax.crypto.spec.SecretKeySpec;
import java.security.MessageDigest;
import java.security.SecureRandom;
import java.util.Arrays;
import java.util.Base64;

class AeadOracle {
    private static final int NONCE = 12;
    static byte[] keyOf(String s) throws Exception {
        byte[] h = MessageDigest.getInstance("SHA-256").digest(s.getBytes("UTF-8"));
        return Arrays.copyOf(h, 16);
    }
    static String emit(String pt, byte[] k) throws Exception {
        byte[] nonce = new byte[NONCE];
        new SecureRandom().nextBytes(nonce);
        Cipher c = Cipher.getInstance("AES/GCM/NoPadding");
        c.init(Cipher.ENCRYPT_MODE, new SecretKeySpec(k, "AES"), new GCMParameterSpec(128, nonce));
        byte[] body = c.doFinal(pt.getBytes("UTF-8"));     // ciphertext concatenated with auth tag
        byte[] all = new byte[NONCE + body.length];
        System.arraycopy(nonce, 0, all, 0, NONCE);
        System.arraycopy(body, 0, all, NONCE, body.length);
        return Base64.getEncoder().encodeToString(all);
    }
    static String check(String cookie, byte[] k) {
        try {
            byte[] all = Base64.getDecoder().decode(cookie);
            byte[] nonce = Arrays.copyOfRange(all, 0, NONCE);
            byte[] body  = Arrays.copyOfRange(all, NONCE, all.length);
            Cipher c = Cipher.getInstance("AES/GCM/NoPadding");
            c.init(Cipher.DECRYPT_MODE, new SecretKeySpec(k, "AES"), new GCMParameterSpec(128, nonce));
            return Base64.getEncoder().encodeToString(c.doFinal(body));
        } catch (Exception e) {
            return "";                                     // AEADBadTagException -> uniform empty
        }
    }
